-- ============================================================
-- 1. Add missing user_id columns to existing tables
-- ============================================================
ALTER TABLE tags
  ADD COLUMN IF NOT EXISTS user_id UUID DEFAULT auth.uid();

ALTER TABLE habits
  ADD COLUMN IF NOT EXISTS user_id UUID DEFAULT auth.uid();

ALTER TABLE habit_completions
  ADD COLUMN IF NOT EXISTS user_id UUID DEFAULT auth.uid();

-- Verify: run this to confirm columns were added
