-- ============================================================
CREATE TABLE IF NOT EXISTS tasks (
  id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
  user_id UUID DEFAULT auth.uid() NOT NULL,
  title TEXT NOT NULL,
  status TEXT NOT NULL DEFAULT 'pending' CHECK (status IN ('pending', 'completed')),
  scheduled_for DATE NOT NULL,
  duration_minutes INTEGER,
  created_at TIMESTAMPTZ DEFAULT now()
);

CREATE INDEX IF NOT EXISTS idx_tasks_user_id ON tasks(user_id);
CREATE INDEX IF NOT EXISTS idx_tasks_scheduled_for ON tasks(scheduled_for);
CREATE INDEX IF NOT EXISTS idx_tasks_status ON tasks(status);

-- ============================================================
-- 2. Enable RLS
-- ============================================================
ALTER TABLE tasks ENABLE ROW LEVEL SECURITY;

-- ============================================================
-- 3. Drop stale policies (safe to re-run)
-- ============================================================
DROP POLICY IF EXISTS "Public access" ON tasks;
DROP POLICY IF EXISTS "User owns data" ON tasks;

-- ============================================================
-- 4. Create user-scoped RLS policies
-- ============================================================
DROP POLICY IF EXISTS "User owns data" ON tasks;
CREATE POLICY "User owns data" ON tasks
  FOR ALL USING (auth.uid() = user_id)
  WITH CHECK (auth.uid() = user_id);


-- ──── lib\supabase-finance-migration.sql ────

-- Run this in your Supabase SQL Editor (Dashboard > SQL Editor)
-- v2 — Merged ISA/JISA into single type with is_jisa flag + contribution tracking

-- 1. Accounts table
CREATE TABLE IF NOT EXISTS accounts (
  id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
  user_id UUID DEFAULT auth.uid(),
  name TEXT NOT NULL,
  type TEXT NOT NULL CHECK (type IN ('savings', 'cash', 'investment', 'isa')),
  balance DECIMAL(12, 2) NOT NULL DEFAULT 0.00,
  interest_rate DECIMAL(5, 2),
  is_jisa BOOLEAN DEFAULT false,
  birth_date DATE,
  contribution_ytd DECIMAL(12, 2) DEFAULT 0.00,
  contribution_year INTEGER,
  created_at TIMESTAMPTZ DEFAULT now(),
  updated_at TIMESTAMPTZ DEFAULT now()
);

-- 2. Transactions table
CREATE TABLE IF NOT EXISTS transactions (
  id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
  user_id UUID DEFAULT auth.uid(),
  account_id UUID REFERENCES accounts(id) ON DELETE CASCADE NOT NULL,
  type TEXT NOT NULL CHECK (type IN ('income', 'expense', 'transfer')),
  amount DECIMAL(12, 2) NOT NULL,
  category TEXT NOT NULL,
  description TEXT,
  date DATE NOT NULL DEFAULT CURRENT_DATE,
  transfer_to_account_id UUID REFERENCES accounts(id) ON DELETE SET NULL,
  created_at TIMESTAMPTZ DEFAULT now()
);

-- 3. Indexes
CREATE INDEX IF NOT EXISTS idx_accounts_user_id ON accounts(user_id);
CREATE INDEX IF NOT EXISTS idx_transactions_user_id ON transactions(user_id);
CREATE INDEX IF NOT EXISTS idx_transactions_account_id ON transactions(account_id);
CREATE INDEX IF NOT EXISTS idx_transactions_date ON transactions(date DESC);

-- 4. Enable RLS
ALTER TABLE accounts ENABLE ROW LEVEL SECURITY;
ALTER TABLE transactions ENABLE ROW LEVEL SECURITY;

-- 5. Drop old policies before creating new ones
DROP POLICY IF EXISTS "User owns accounts" ON accounts;
DROP POLICY IF EXISTS "User owns transactions" ON transactions;

-- 6. RLS policies — rows scoped to the authenticated user
DROP POLICY IF EXISTS "User owns accounts" ON accounts;
CREATE POLICY "User owns accounts" ON accounts
  FOR ALL USING (auth.uid() = user_id) WITH CHECK (auth.uid() = user_id);

DROP POLICY IF EXISTS "User owns transactions" ON transactions;
CREATE POLICY "User owns transactions" ON transactions
  FOR ALL USING (auth.uid() = user_id) WITH CHECK (auth.uid() = user_id);

-- 7. Migration helper: convert old JISA-type accounts to new format
-- Run this once if you had existing 'JISA' type accounts:
-- UPDATE accounts SET type = 'isa', is_jisa = true WHERE type = 'JISA';
-- UPDATE accounts SET type = 'isa' WHERE type = 'ISA';


-- ──── lib\supabase-future-transactions-migration.sql ────

-- Run this in your Supabase SQL Editor (Dashboard > SQL Editor)
-- Adds future_transactions table for persisting projected events

-- 1. Future transactions table
-- Stores income/expense/transfer events scheduled at a future age for projection purposes
CREATE TABLE IF NOT EXISTS future_transactions (
  id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
  user_id UUID DEFAULT auth.uid(),
  account_id UUID REFERENCES accounts(id) ON DELETE CASCADE NOT NULL,
  age INTEGER NOT NULL CHECK (age > 0),
  description TEXT NOT NULL,
  amount DECIMAL(12, 2) NOT NULL DEFAULT 0,
  to_account_id UUID REFERENCES accounts(id) ON DELETE SET NULL,
  transfer_mode TEXT CHECK (transfer_mode IN ('fixed', 'percent', 'above_threshold')),
  transfer_value DECIMAL(12, 2),
  created_at TIMESTAMPTZ DEFAULT now()
);

-- 2. Indexes
CREATE INDEX IF NOT EXISTS idx_future_transactions_user_id ON future_transactions(user_id);
CREATE INDEX IF NOT EXISTS idx_future_transactions_age ON future_transactions(age);

-- 3. Enable RLS
ALTER TABLE future_transactions ENABLE ROW LEVEL SECURITY;

-- 4. Drop old policies before creating new ones
DROP POLICY IF EXISTS "User owns future transactions" ON future_transactions;

-- 5. RLS policy — rows scoped to the authenticated user
DROP POLICY IF EXISTS "User owns future transactions" ON future_transactions;
CREATE POLICY "User owns future transactions" ON future_transactions
  FOR ALL USING (auth.uid() = user_id) WITH CHECK (auth.uid() = user_id);


-- ──── lib\supabase-time-management-migration.sql ────

-- Time Management — Phase 1 schema foundation
--
-- Additions:
--   1. habits.duration_minutes — optional estimated duration per habit.
--      The "smart habits" logic (curfew-based AVAILABLE/LOCKED states
--      and live recommendations) reads this column to decide whether a
--      habit fits in the remaining free time before curfew.
--   2. habits.priority — optional integer 0-3 (0 = no priority, 1 = low,
--      2 = medium, 3 = high). Drives ordering in the recommendations
--      banner; higher priority = appears earlier.
--
-- New table:
--   3. calendar_events — fixed commitments ONLY (school, tennis,
--      football, appointments, holidays, manually created events).
--      Habits are intentionally NOT stored here — they remain
--      checkbox-based daily priorities; the calendar is reserved for
--      blocks that genuinely consume time.

-- ─── habits: add duration + priority ───────────────────────────────

ALTER TABLE habits
  ADD COLUMN IF NOT EXISTS duration_minutes INTEGER
    CHECK (duration_minutes IS NULL OR duration_minutes > 0),
  ADD COLUMN IF NOT EXISTS priority SMALLINT
    DEFAULT 0
    CHECK (priority BETWEEN 0 AND 3);

COMMENT ON COLUMN habits.duration_minutes IS
  'Estimated minutes to complete the habit. Drives curfew fit analysis.';
COMMENT ON COLUMN habits.priority IS
  '0 = no priority, 1 = low, 2 = medium, 3 = high. Used for recommendation ordering.';

-- ─── calendar_events: fixed commitments only ────────────────────────

CREATE TABLE IF NOT EXISTS calendar_events (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  user_id UUID NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE,
  title TEXT NOT NULL,
  start_at TIMESTAMPTZ NOT NULL,
  end_at TIMESTAMPTZ NOT NULL,
  -- Optional visual + placement metadata
  location TEXT,
  notes TEXT,
  color TEXT,                -- e.g. 'bg-rose-500' or null for default
  -- Used to distinguish fixed manual blocks from auto-imported ones
  -- (Google Calendar, ICS, etc.) — Phase 4.
  source TEXT DEFAULT 'manual',
  CONSTRAINT calendar_events_end_after_start CHECK (end_at > start_at),
  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  updated_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

CREATE INDEX IF NOT EXISTS calendar_events_user_start_idx
  ON calendar_events (user_id, start_at);

ALTER TABLE calendar_events ENABLE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS "Users read their own calendar_events" ON calendar_events;
DROP POLICY IF EXISTS "Users read their own calendar_events" ON calendar_events;
CREATE POLICY "Users read their own calendar_events" ON calendar_events
  FOR SELECT USING (auth.uid() = user_id);

DROP POLICY IF EXISTS "Users insert their own calendar_events" ON calendar_events;
DROP POLICY IF EXISTS "Users insert their own calendar_events" ON calendar_events;
CREATE POLICY "Users insert their own calendar_events" ON calendar_events
  FOR INSERT WITH CHECK (auth.uid() = user_id);

DROP POLICY IF EXISTS "Users update their own calendar_events" ON calendar_events;
DROP POLICY IF EXISTS "Users update their own calendar_events" ON calendar_events;
CREATE POLICY "Users update their own calendar_events" ON calendar_events
  FOR UPDATE USING (auth.uid() = user_id);

DROP POLICY IF EXISTS "Users delete their own calendar_events" ON calendar_events;
DROP POLICY IF EXISTS "Users delete their own calendar_events" ON calendar_events;
CREATE POLICY "Users delete their own calendar_events" ON calendar_events
  FOR DELETE USING (auth.uid() = user_id);

